INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (10041001, "光属性のキャラが４体以上編成されているとき、キャラの属性ボーナスが強化される。光属性以外の属性ボーナスを無効化する。", 4100410, "光属性ボーナス特大アップ", 15);
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (10041002, "すべてのモンスターが一度の行動で受けるダメージ値を減衰させる。ダメージ値が上昇するほど減衰率も上昇する。", 4100410, "ダメージ減衰", 18);
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (10041003, "バトル開始時、すべてのモンスターの物理防御力をアップさせる。この効果は物理防御力ダウンの影響を受けない。", 4100410, "物理防御力（ダウン不可）アップ", "boss_def_lower_limit");
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (10041004, "バトル開始時、すべてのモンスターの魔法防御力をアップさせる。この効果は魔法防御力ダウンの影響を受けない。", 4100410, "魔法防御力（ダウン不可）アップ", "boss_magic_def_lower_limit");
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (10041005, "バトル開始時、すべてのモンスターがＴＰダウン\n75％カット状態になる。", 4100410, "ＴＰダウンカット", "boss_tp_down_cut");
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (10041006, "バトル開始時、すべてのキャラのＴＰ上昇をダウンさせる。", 4100410, "ＴＰ上昇ダウン", 3);
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (10041007, "バトル開始時、すべてのキャラのＨＰ吸収をダウンさせる。", 4100410, "ＨＰ吸収ダウン", 9);
